import { defineAgent } from "eve";

export default defineAgent({
  model: "openai/gpt-5.4-mini",
});

import { defineChannel, POST } from "eve/channels";

import slack from "./slack";

type IntakeBody = {
  text?: string;
  source?: string;
};

/**
 * Custom ingress: POST any text payload, hand it to Slack for a classified
 * summary. Mounted at POST /eve/v1/intake/submit.
 */
export default defineChannel({
  routes: [
    POST("/eve/v1/intake/submit", async (req, args) => {
      const secret = process.env.WEBHOOK_SECRET;
      if (secret) {
        const auth = req.headers.get("authorization") ?? "";
        if (auth !== `Bearer ${secret}`) {
          return Response.json({ error: "unauthorized" }, { status: 401 });
        }
      }

      const channelId = process.env.SLACK_SUMMARY_CHANNEL_ID;
      if (!channelId) {
        return Response.json(
          { error: "SLACK_SUMMARY_CHANNEL_ID is not set" },
          { status: 500 }
        );
      }

      let body: IntakeBody;
      try {
        body = (await req.json()) as IntakeBody;
      } catch {
        return Response.json({ error: "invalid JSON body" }, { status: 400 });
      }

      const text = typeof body.text === "string" ? body.text.trim() : "";
      if (!text) {
        return Response.json(
          { error: "body.text is required (non-empty string)" },
          { status: 400 }
        );
      }

      const source =
        typeof body.source === "string" && body.source.trim()
          ? body.source.trim()
          : "webhook";

      args.waitUntil(
        args.receive(slack, {
          message: [
            "Summarize and classify this inbound submission.",
            `Source: ${source}`,
            "",
            text,
          ].join("\n"),
          target: { channelId },
          auth: {
            authenticator: "intake-webhook",
            principalType: "service",
            principalId: source,
            attributes: { source },
          },
        })
      );

      return Response.json({ ok: true });
    }),
  ],
});

import { connectSlackCredentials } from "@vercel/connect/eve";
import { slackChannel } from "eve/channels/slack";

// Replace the UID with your own Slack Connect client. See SETUP.md.
export default slackChannel({
  credentials: connectSlackCredentials("slack/webhook-summarizer-starter"),
});

import { defineEval } from "eve/evals";
import { includes } from "eve/evals/expect";

export default defineEval({
  description: "Classifies a support ticket into the required summary format.",
  async test(t) {
    await t.send(
      [
        "Summarize and classify this inbound submission.",
        "Source: contact-form",
        "",
        "Hi — I cannot log in after resetting my password. Error says",
        '"invalid credentials" even though I just set a new one. Urgent!',
      ].join("\n")
    );
    t.succeeded();
    t.check(t.reply, includes(/Intake/i));
    t.check(t.reply, includes(/Priority:/i));
    t.check(t.reply, includes(/support|bug/i)).soft();
  },
});

import { defineEvalConfig } from "eve/evals";

export default defineEvalConfig({
  maxConcurrency: 1,
  timeoutMs: 120_000,
});
